  const pendingSnakeClaims=(pending||[]).filter(e=>e.snake_player_name).map(e=>({type:'pending_score',key:`pending-${e.id}`,...e}));
  const storedSnakeClaims=(snakeLog||[]).filter(s=>s.confirmed!==true).map(s=>({type:'snake_log',key:`snake-${s.id}`,...s}));
  const snakeClaims=[...pendingSnakeClaims,...storedSnakeClaims];
  const vp=rankings.find(p=>p.id===selId);
  function appDate(value){
    if(typeof value==='string'){
      const [y,m,d]=value.slice(0,10).split('-').map(Number);
      if(y&&m&&d)return new Date(y,m-1,d);
    }
    return new Date(value);
  }
  function lastQualifyingNightOfMonth(year,month){
    const lastDay=new Date(year,month+1,0);
    for(let d=new Date(lastDay);d.getMonth()===month;d.setDate(d.getDate()-1)){
      if(d.getDay()===3||d.getDay()===6||d.getDay()===0){
        const lockDate=new Date(d);
        lockDate.setHours(22,0,0,0);
        return lockDate;
      }
    }
    return null;
  }
  function getPotmForMonth(year,month){
    return players.map(p=>{
      const ms=scores.filter(s=>{const d=appDate(s.date);return s.player_id===p.id&&d.getMonth()===month&&d.getFullYear()===year&&!s.is_double_chip;});
      const allSorted=[...ms].sort((a,b)=>appDate(b.date)-appDate(a.date));
      const top3=[...ms].sort((a,b)=>b.points-a.points).slice(0,3);
      const avg=top3.length>0?(top3.reduce((t,s)=>t+s.points,0)/top3.length):0;
      const qualified=top3.length>=3;
      return{...p,allMonthScores:allSorted,top3,avg:Math.round(avg*10)/10,roundsPlayed:ms.length,qualified};
    }).filter(p=>p.roundsPlayed>0).sort((a,b)=>{
      if(a.qualified&&!b.qualified)return -1;
      if(!a.qualified&&b.qualified)return 1;
      return b.avg-a.avg;
    });
  }
  function getPotmWinners(year,month,asOf=new Date()){
    const lockDate=lastQualifyingNightOfMonth(year,month);
    if(!lockDate||asOf<lockDate)return[];
    const data=getPotmForMonth(year,month).filter(p=>p.qualified);
    if(data.length===0)return[];
    return data.filter(p=>p.avg===data[0].avg);
  }
  function getSeasonHighScoreLeaders(){
    const hsData=players.map(p=>{
      const ps=scores.filter(s=>s.player_id===p.id&&!s.is_double_chip);
      const best=ps.length>0?ps.reduce((a,b)=>b.points>a.points?b:a):null;
      return{...p,best,rounds:scores.filter(s=>s.player_id===p.id).length};
    }).filter(p=>p.best).sort((a,b)=>b.best.points-a.best.points);
    if(hsData.length===0)return[];
    return hsData.filter(p=>p.best.points===hsData[0].best.points);
  }
  function calcPrizePot(){
    return players.reduce((t,p)=>{
      const rounds=scores.filter(s=>s.player_id===p.id).length;
      return t+10+(Math.max(0,rounds-8)*2);
    },0);
  }
  function getPrizeRows(){
    const now=new Date();
    const prizeMap=new Map();
    function addPrize(player,award,status,amount,detail){
      if(!prizeMap.has(player))prizeMap.set(player,{player,confirmed:[],projected:[],confirmedAmount:0,projectedAmount:0,totalAmount:0});
      const row=prizeMap.get(player);
      const item={award,amount,detail};
      if(status==='Confirmed'){
        row.confirmed.push(item);
        row.confirmedAmount+=amount;
      }else{
        row.projected.push(item);
        row.projectedAmount+=amount;
      }
      row.totalAmount+=amount;
    }
    const potmStart={y:2026,m:3};
    for(let y=potmStart.y;y<=now.getFullYear();y++){
      const startM=y===potmStart.y?potmStart.m:0;
      const endM=y===now.getFullYear()?now.getMonth():11;
      for(let m=startM;m<=endM;m++){
        const winners=getPotmWinners(y,m,now);
        if(winners.length>0){
          const monthName=new Date(y,m,1).toLocaleString('en-GB',{month:'long'});
          const amount=10/winners.length;
          winners.forEach(w=>addPrize(w.name,`${monthName} Player of the Month`,'Confirmed',amount,winners.length>1?'split monthly prize':'monthly prize'));
        }
      }
    }
    const potmPaid=Array.from(prizeMap.values()).reduce((t,r)=>t+r.confirmedAmount,0);
    const highLeaders=getSeasonHighScoreLeaders();
    if(highLeaders.length>0){
      const amount=20/highLeaders.length;
      highLeaders.forEach(w=>addPrize(w.name,'Season High Score','Projected',amount,`${w.best.points} pts`));
    }
    const highPrize=highLeaders.length>0?20:0;
    const remainder=Math.max(0,calcPrizePot()-potmPaid-highPrize);
    if(rankings.length>0){
      const firstTotal=rankings[0].total;
      const firsts=rankings.filter(p=>p.total===firstTotal);
      const seconds=rankings.filter(p=>p.total<firstTotal);
      const secondTotal=seconds[0]?.total;
      const secondGroup=secondTotal!==undefined?rankings.filter(p=>p.total===secondTotal):[];
      firsts.forEach(w=>addPrize(w.name,'League Winner','Projected',(remainder*0.7)/firsts.length,`${w.total} pts`));
      secondGroup.forEach(w=>addPrize(w.name,'League Runner-up','Projected',(remainder*0.3)/secondGroup.length,`${w.total} pts`));
    }
    return Array.from(prizeMap.values()).sort((a,b)=>b.totalAmount-a.totalAmount||a.player.localeCompare(b.player));
  }

