                      <div style={{fontSize:24,color:e.is_double_chip?'#fbbf24':'#fbbf24',minWidth:44,textAlign:'center',background:'rgba(251,191,36,0.12)',borderRadius:8,padding:'4px 8px'}}>{e.points}</div>
                      <div>
